import { Component } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { AlertService } from "src/app/core/services/alert.service";
import { InputMaskingService } from "src/app/core/services/input-masking.service";
import { LoansService } from "src/app/core/services/loans.service";
import {
  installmentCalculationRequest,
  installmentCalculationResponse,
} from "src/app/views/Models/Loan/LoanCalc";
import { LoanTypeRef } from "src/app/views/Models/Loan/LoanType";
interface FormStatus {
  visible: boolean;
  valid: boolean;
}

@Component({
  selector: "app-loan-calculator",
  templateUrl: "./loan-calculator.page.html",
  styleUrls: ["./loan-calculator.page.scss"],
})
export class loancalculatorPage {
  constructor(
    private formBuilder: FormBuilder,
    private alertService: AlertService,
    private loansService: LoansService,
    public inputMaskingService: InputMaskingService
  ) {}
  //#region Variables
  showLoader: boolean = false;
  calculationFormStatus: FormStatus = { valid: false, visible: true };
  gridFormStatus: FormStatus = { valid: false, visible: false };
  loanTypesModel: LoanTypeRef[];
  installmentCalculationResponse: installmentCalculationResponse[];
  //#endregion

  async ngOnInit() {
    this.showLoader = true;
    this.loanTypesModel = await this.loansService.getAllActiveLoanTypes();
    this.showLoader = false;
  }
  calculationForm: FormGroup = this.formBuilder.group({
    loanType: ["", [Validators.required]],
    requestNumber: ["", [Validators.required, Validators.pattern("[0-9]*")]],
    requestAmount: [
      "",
      [Validators.required, Validators.pattern("[0-9]*.[0-9]*")],
    ],
  });

  async SubmitForm() {
    this.calculationFormStatus.valid = true;
    if (!this.calculationForm.valid) {
      return;
    }
    let installmentCalculationRequest: installmentCalculationRequest = {
      req_am: Number(this.calculationForm.value.requestAmount).toString(),
      req_no: this.calculationForm.value.requestNumber.toString(),
      loan_type: this.calculationForm.value.loanType,
    };
    try {
      this.showLoader = true;
      this.installmentCalculationResponse =
        await this.loansService.calculateLoanInstallment(
          installmentCalculationRequest
        );
      this.gridFormStatus.visible = true;
      this.showLoader = false;
    } catch (error) {
      this.showLoader = false;
      this.alertService.showAlertError(error.message, false);
    }
  }

  enterClick(event: KeyboardEvent) {
    if (event.key == "Enter") {
      this.SubmitForm();
    }
  }
}
